source.buildspec:
version: 0.2
phases:
  pre_build:
    commands:
      - tar -xzf sha256-T7iSdNuO_vTAJsuH2uQcjFPe93mJ7CuOldFH7FRtLaI_.tar.gz -C $CODEBUILD_SRC_DIR
      - rm sha256-T7iSdNuO_vTAJsuH2uQcjFPe93mJ7CuOldFH7FRtLaI_.tar.gz
      - mkdir -p /root/.docker
      - echo '{"credHelpers":{"public.ecr.aws":"ecr-login","381492210770.dkr.ecr.us-west-2.amazonaws.com":"ecr-login"}}' > /root/.docker/config.json
      - mkdir -p /etc/docker/ && echo '{"registry-mirrors":["https://381492210770.dkr.ecr.us-west-2.amazonaws.com/defang-html-css-js-test280dd33","http://localhost:5000"]}' > /etc/docker/daemon.json
      - |-
        echo '
        [registry."docker.io"]
          mirrors = [
            "https://381492210770.dkr.ecr.us-west-2.amazonaws.com/defang-html-css-js-test280dd33", "http://localhost:5000"
          ]
        ' > /tmp/buildkitd.toml
      - kill -HUP $(pidof dockerd)
      - |-
        cat > /tmp/nginx.conf.tmpl << EOF
        events {}
        http {
            server {

                set \$token "";
        __TOKEN__

                listen 80;
                location = /v2/ {
                    proxy_pass https://public.ecr.aws/v2/;
                    proxy_intercept_errors on;
                    proxy_set_header Authorization "Bearer \$token";
                    proxy_ssl_server_name on;

                    error_page 404 = @fallback;
                }

                location ~ ^/v2/(.+) {
                    # Capture the rest of the path
                    set \$rest \$1;

                    # Build upstream path: /v2/docker/<rest>
                    proxy_pass https://public.ecr.aws/v2/docker/\$rest;
                    proxy_intercept_errors on;
                    proxy_set_header Authorization "Bearer \$token";
                    proxy_ssl_server_name on;

                    error_page 404 = @fallback;
                }

                location @fallback {
                    proxy_pass https://registry-1.docker.io;
                    proxy_intercept_errors on;
                    proxy_ssl_server_name on;

                    error_page 429 = @throttled;
                }

                location @throttled {
                    return 429 "Docker Hub rate limit exceeded. Please do `docker login` before deployment.\n";
                }
            }
        }

        EOF
      - TOKEN_BLOCK=$(echo "https://public.ecr.aws" | docker-credential-ecr-login get | jq -j '"\(.Username):\(.Secret)"' | base64 -w 1024 | awk '{ print "set $token \"${token}" $0 "\";" }')
      - awk -v token_block="$TOKEN_BLOCK" '{ if ($0 ~ /__TOKEN__/) { print token_block } else { print } }' /tmp/nginx.conf.tmpl > /tmp/nginx.conf
      - docker run -d -p 5000:80 --restart=always --name dockerhub-ecr-mirror -v /tmp/nginx.conf:/etc/nginx/nginx.conf:ro public.ecr.aws/nginx/nginx:stable-alpine
      - sleep 3
      - docker buildx create --use --driver=docker-container --buildkitd-config=/tmp/buildkitd.toml --driver-opt network=host --use --platform linux/amd64
  build:
    commands:
      - echo Building the Docker image...
      - docker buildx build -t 381492210770.dkr.ecr.us-west-2.amazonaws.com/html-css-js/test2-build:app-image-c2165c65-x86_64 -f Dockerfile --push --cache-from=type=registry,ref=381492210770.dkr.ecr.us-west-2.amazonaws.com/html-css-js/test2-build:defang-cache --cache-to=type=registry,image-manifest=true,oci-mediatypes=true,mode=max,ref=381492210770.dkr.ecr.us-west-2.amazonaws.com/html-css-js/test2-build:defang-cache --platform linux/amd64  ${CODEBUILD_SRC_DIR}
